package com.vidaysalud.veterinaria.mascotaservicio.repository; import com.vidaysalud.veterinaria.mascotaservicio.model.Mascota; import org.springframework.data.jpa.repository.JpaRepository; import java.util.List; public interface MascotaRepository extends JpaRepository<Mascota,Integer>{List<Mascota> findByIdCliente(Integer idCliente); List<Mascota> findByEspecieIgnoreCase(String especie);}